import React, { useMemo, useState } from "react";
import Dashboard from "./Dashboard";
import Upload from "./Upload";
import Preview from "./Preview";
import Calendar from "./Calendar";

function App() {
  const [screen, setScreen] = useState("dashboard");
  const [activities, setActivities] = useState([]);
  const [draftActivity, setDraftActivity] = useState(null);

  const upcomingActivity = useMemo(() => {
    const now = new Date();
    return [...activities]
      .filter((activity) => new Date(activity.dateTime) >= now)
      .sort((a, b) => new Date(a.dateTime) - new Date(b.dateTime))[0];
  }, [activities]);

  const openUploadScreen = () => setScreen("upload");
  const openCalendarScreen = () => setScreen("calendar");

  const handlePreviewRequest = (payload) => {
    setDraftActivity(payload);
    setScreen("preview");
  };

  const handleConfirmActivity = (confirmedActivity) => {
    setActivities((prev) => [...prev, confirmedActivity]);
    setDraftActivity(null);
    setScreen("calendar");
  };

  const handleBackToDashboard = () => {
    setDraftActivity(null);
    setScreen("dashboard");
  };

  const pageContainerStyle = {
    maxWidth: 860,
    margin: "2rem auto",
    background: "#ffffff",
    borderRadius: 16,
    padding: "1.5rem",
    boxShadow: "0 8px 25px rgba(15, 23, 42, 0.08)",
    border: "1px solid #e2e8f0"
  };

  const appStyle = {
    minHeight: "100vh",
    background: "linear-gradient(180deg, #f8fafc 0%, #eff6ff 100%)",
    fontFamily: "Segoe UI, Roboto, Arial, sans-serif",
    color: "#0f172a",
    padding: "1rem"
  };

  const titleStyle = {
    margin: "0 0 0.5rem 0",
    fontSize: "1.5rem",
    fontWeight: 700
  };

  const subtitleStyle = {
    margin: "0 0 1.5rem 0",
    color: "#475569",
    fontSize: "0.95rem"
  };

  return (
    <div style={appStyle}>
      <div style={pageContainerStyle}>
        <h1 style={titleStyle}>Parentpal</h1>
        <p style={subtitleStyle}>
        Plan smarter, prepare faster, and never miss an activity with weather-ready checklists.
        </p>

        {screen === "dashboard" && (
          <Dashboard
            upcomingActivity={upcomingActivity}
            onAddActivity={openUploadScreen}
            onViewCalendar={openCalendarScreen}
          />
        )}

        {screen === "upload" && (
          <Upload
            onNext={handlePreviewRequest}
            onBack={handleBackToDashboard}
          />
        )}

        {screen === "preview" && draftActivity && (
          <Preview
            draftActivity={draftActivity}
            onConfirm={handleConfirmActivity}
            onBack={() => setScreen("upload")}
          />
        )}

        {screen === "calendar" && (
          <Calendar
            activities={activities}
            onAddActivity={openUploadScreen}
            onBack={handleBackToDashboard}
          />
        )}
      </div>
    </div>
  );
}

export default App;
